**Step 3: Create ContentView with fullscreen and ESC handler**

File: `BauhasClock/Sources/Views/ContentView.swift`

```swift
import SwiftUI

struct ContentView: View {
    @State private var isFullScreen = false

    var body: some View {
        ZStack {
            // Background color
            Color(red: 0.616, green: 0.851, blue: 0.773)
                .ignoresSafeArea()

            // Clock view
            ClockView()
        }
        .onReceive(Timer.publish(every: 0.01, on: .main, in: .common).autoconnect()) { _ in
            // Trigger view updates for animation
        }
        .onAppear {
            NSApplication.shared.mainWindow?.toggleFullScreen(nil)
        }
        .keyboardShortcut(.cancelAction)
        .onKeyDown { event in
            if event.keyCode == 53 { // ESC key
                NSApplication.shared.terminate(nil)
            }
            return false
        }
    }
}

