import SwiftUI

class PerformanceMonitor: ObservableObject {
    @Published var fps: Double = 60

    private var frameCount = 0
    private var lastTime = Date()

    func tick() {
        frameCount += 1
        let now = Date()
        let elapsed = now.timeIntervalSince(lastTime)

        if elapsed >= 1.0 {
            fps = Double(frameCount) / elapsed
            frameCount = 0
            lastTime = now
        }
    }
}
